<template><div class="login-shell"><div class="login-card"><div class="brand-mark">麒麟</div><h1>麒麟智维盾</h1><p>安全智能运维控制台</p><el-form @submit.prevent="submit"><el-input v-model="username" placeholder="用户名"/><el-input v-model="password" type="password" show-password placeholder="密码"/><el-alert v-if="error" :title="error" type="error" :closable="false"/><el-button native-type="submit" type="primary" :loading="loading">安全登录</el-button></el-form></div></div></template>
<script setup lang="ts">import{ref}from"vue";import{useRouter}from"vue-router";import{useSession}from"../stores/session";const username=ref(""),password=ref(""),error=ref(""),loading=ref(false),router=useRouter(),session=useSession();async function submit(){loading.value=true;error.value="";try{await session.login(username.value,password.value);await router.push("/")}catch(e){error.value=e instanceof Error?e.message:"登录失败"}finally{password.value="";loading.value=false}}</script>
